namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public int DepartmentId { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Full name is required.")]
    [StringLength(100)]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Za-z0-9]+$", ErrorMessage = "Student ID must be alphanumeric.")]
    [StringLength(20)]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollments = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Pure and applied mathematics, including statistics and data analysis." },
            new() { Id = 3, Code = "PHYS", Name = "Physics", Description = "Understanding the fundamental laws governing the natural world." },
            new() { Id = 4, Code = "ENG", Name = "English", Description = "Literature, writing, and linguistic analysis." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Exploration of historical events, cultures, and societies." },
        };

        _courses = new List<Course>
        {
            new()
            {
                Id = 1, DepartmentId = 1, Code = "CS 101", Title = "Introduction to Programming",
                Description = "Foundational course covering variables, control flow, functions, and basic data structures using Python.",
                Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", IsFeatured = true,
                InstructorName = "Dr. Alice Chen",
                InstructorBio = "Dr. Chen holds a Ph.D. in Computer Science from MIT and has over 15 years of teaching experience in introductory programming and software engineering."
            },
            new()
            {
                Id = 2, DepartmentId = 1, Code = "CS 201", Title = "Data Structures & Algorithms",
                Description = "In-depth study of arrays, linked lists, trees, graphs, sorting, and algorithmic complexity.",
                Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", IsFeatured = true,
                InstructorName = "Dr. Bob Martinez",
                InstructorBio = "Dr. Martinez specializes in algorithm design and competitive programming. He previously worked at Google Research."
            },
            new()
            {
                Id = 3, DepartmentId = 1, Code = "CS 310", Title = "Operating Systems",
                Description = "Concepts of process management, memory management, file systems, and concurrency.",
                Credits = 3, Schedule = "Mon/Wed 1:00–2:20 PM", IsFeatured = false,
                InstructorName = "Prof. Carol Singh",
                InstructorBio = "Prof. Singh is a systems researcher with publications in SOSP and OSDI, focusing on distributed operating systems."
            },
            new()
            {
                Id = 4, DepartmentId = 1, Code = "CS 450", Title = "Machine Learning",
                Description = "Introduction to supervised and unsupervised learning, neural networks, and model evaluation.",
                Credits = 3, Schedule = "Tue/Thu 2:00–3:20 PM", IsFeatured = true,
                InstructorName = "Dr. Alice Chen",
                InstructorBio = "Dr. Chen holds a Ph.D. in Computer Science from MIT and has over 15 years of teaching experience in introductory programming and software engineering."
            },
            new()
            {
                Id = 5, DepartmentId = 2, Code = "MATH 101", Title = "Calculus I",
                Description = "Limits, derivatives, and integrals of single-variable functions with applications.",
                Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", IsFeatured = true,
                InstructorName = "Dr. David Park",
                InstructorBio = "Dr. Park received his doctorate from Stanford and has authored two textbooks on introductory calculus."
            },
            new()
            {
                Id = 6, DepartmentId = 2, Code = "MATH 201", Title = "Linear Algebra",
                Description = "Vector spaces, linear transformations, matrices, determinants, and eigenvalues.",
                Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", IsFeatured = false,
                InstructorName = "Dr. Emily Zhao",
                InstructorBio = "Dr. Zhao researches numerical linear algebra and has been teaching undergraduate mathematics for a decade."
            },
            new()
            {
                Id = 7, DepartmentId = 2, Code = "MATH 330", Title = "Probability & Statistics",
                Description = "Probability theory, random variables, distributions, hypothesis testing, and regression.",
                Credits = 3, Schedule = "Mon/Wed 3:00–4:20 PM", IsFeatured = false,
                InstructorName = "Dr. David Park",
                InstructorBio = "Dr. Park received his doctorate from Stanford and has authored two textbooks on introductory calculus."
            },
            new()
            {
                Id = 8, DepartmentId = 3, Code = "PHYS 101", Title = "General Physics I",
                Description = "Mechanics, thermodynamics, and waves with laboratory experiments.",
                Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", IsFeatured = false,
                InstructorName = "Dr. Frank Novak",
                InstructorBio = "Dr. Novak is an experimental physicist who spent ten years at CERN before joining the faculty."
            },
            new()
            {
                Id = 9, DepartmentId = 3, Code = "PHYS 201", Title = "Electromagnetism",
                Description = "Electric fields, magnetic fields, Maxwell's equations, and electromagnetic waves.",
                Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", IsFeatured = false,
                InstructorName = "Dr. Grace Liu",
                InstructorBio = "Dr. Liu is a theoretical physicist whose research focuses on quantum electrodynamics and photonics."
            },
            new()
            {
                Id = 10, DepartmentId = 4, Code = "ENG 101", Title = "Composition & Rhetoric",
                Description = "Fundamentals of academic writing, argumentation, and critical reading.",
                Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", IsFeatured = false,
                InstructorName = "Prof. Hannah Cole",
                InstructorBio = "Prof. Cole is a published author and writing instructor with expertise in rhetoric and composition studies."
            },
            new()
            {
                Id = 11, DepartmentId = 4, Code = "ENG 220", Title = "American Literature",
                Description = "Survey of major American literary works from the colonial period to the present.",
                Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", IsFeatured = true,
                InstructorName = "Dr. Ian Brooks",
                InstructorBio = "Dr. Brooks specializes in 20th-century American fiction and has published extensively on Faulkner and Morrison."
            },
            new()
            {
                Id = 12, DepartmentId = 5, Code = "HIST 101", Title = "World History to 1500",
                Description = "Survey of global civilizations from ancient times through the late medieval period.",
                Credits = 3, Schedule = "Mon/Wed 10:00–11:20 AM", IsFeatured = false,
                InstructorName = "Dr. Julia Torres",
                InstructorBio = "Dr. Torres is a historian of ancient Mediterranean civilizations with fieldwork experience in Greece and Turkey."
            },
            new()
            {
                Id = 13, DepartmentId = 5, Code = "HIST 250", Title = "Modern European History",
                Description = "Political, social, and cultural developments in Europe from the Enlightenment to the present.",
                Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", IsFeatured = true,
                InstructorName = "Prof. Kevin Walsh",
                InstructorBio = "Prof. Walsh is an expert in modern European political history and has lectured across universities in Europe and North America."
            },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public void SubmitEnrollment(EnrollmentRequest request)
    {
        _enrollments.Add(request);
    }

    public string GetDepartmentName(int departmentId) =>
        _departments.FirstOrDefault(d => d.Id == departmentId)?.Name ?? "Unknown";
}

