<form method="get" action="courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <input type="text" name="search" value="@Search" class="form-control" placeholder="Search by title, code, or instructor…" />
    </div>
    <div class="col-md-4">
        <select name="dept" class="form-select">
            <option value="">All Departments</option>
            @foreach (var d in Catalog.GetDepartments())
            {
                <option value="@d.Id" selected="@(Dept == d.Id)">@d.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Search</button>
    </div>
</form>

@{
    var courses = Catalog.SearchCourses(Search, Dept);
}

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.Code</td>
                    <td>@course.Title</td>
                    <td>@Catalog.GetDepartmentName(course.DepartmentId)</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td><a href="@($"courses/{course.Id}")" class="btn btn-outline-primary btn-sm">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery(Name = "search")]
    public string? Search { get; set; }

    [SupplyParameterFromQuery(Name = "dept")]
    public int? Dept { get; set; }
}

