toolArgs.file_text:
@page "/courses"
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Courses — University Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" action="courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <input type="text" name="search" value="@Search" class="form-control" placeholder="Search by title, code, or instructor…" />
    </div>
    <div class="col-md-4">
        <select name="dept" class="form-select">
            <option value="">All Departments</option>
            @foreach (var d in Catalog.GetDepartments())
            {
                <option value="@d.Id" selected="@(Dept == d.Id)">@d.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Search</button>
    </div>
</form>

@{
    var courses = Catalog.SearchCourses(Search, Dept);
}

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.Code</td>
                    <td>@course.Title</td>
                    <td>@Catalog.GetDepartmentName(course.DepartmentId)</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td><a href="@($"courses/{course.Id}")" class="btn btn-outline-primary btn-sm">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery(Name = "search")]
    public string? Search { get; set; }

    [SupplyParameterFromQuery(Name = "dept")]
    public int? Dept { get; set; }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>@(course?.Title ?? "Course Not Found") — University Course Catalog</PageTitle>

@if (course is null)
{
    <div class="alert alert-warning">Course not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active" aria-current="page">@course.Code</li>
        </ol>
    </nav>

    <h1>@course.Code — @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h4>Description</h4>
            <p>@course.Description</p>

            <h4>Schedule</h4>
            <p>@course.Schedule</p>

            <h4>Credits</h4>
            <p>@course.Credits</p>

            <a href="@($"enroll?courseId={course.Id}")" class="btn btn-success mt-2">Enroll in This Course</a>
        </div>
        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Instructor</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.InstructorName</h6>
                    <p class="card-text">@course.InstructorBio</p>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private UniversityCourseCatalog.Models.Course? course;

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(Id);
    }
}

@page "/departments"
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Departments — University Course Catalog</PageTitle>

<h1>Departments</h1>

<div class="row">
    @foreach (var dept in Catalog.GetDepartments())
    {
        <div class="col-md-6 mb-4">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@dept.Code — @dept.Name</h5>
                    <p class="card-text">@dept.Description</p>
                    <a href="@($"departments/{dept.Id}")" class="btn btn-primary btn-sm">View Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@page "/departments/{Id:int}"
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>@(department?.Name ?? "Department Not Found") — University Course Catalog</PageTitle>

@if (department is null)
{
    <div class="alert alert-warning">Department not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="departments">Departments</a></li>
            <li class="breadcrumb-item active" aria-current="page">@department.Name</li>
        </ol>
    </nav>

    <h1>@department.Code — @department.Name</h1>
    <p class="lead">@department.Description</p>

    var courses = Catalog.GetCoursesByDepartment(department.Id);

    @if (courses.Count == 0)
    {
        <div class="alert alert-info">No courses available in this department.</div>
    }
    else
    {
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Credits</th>
                    <th>Instructor</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in courses)
                {
                    <tr>
                        <td>@course.Code</td>
                        <td>@course.Title</td>
                        <td>@course.Credits</td>
                        <td>@course.InstructorName</td>
                        <td><a href="@($"courses/{course.Id}")" class="btn btn-outline-primary btn-sm">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    [Parameter]
    public int Id { get; set; }

    private UniversityCourseCatalog.Models.Department? department;

    protected override void OnInitialized()
    {
        department = Catalog.GetDepartment(Id);
    }
}

